import{c as t,Q as a,j as n,m as o}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"The Rundown AI — 2026-05-06","description":"","frontmatter":{"title":"The Rundown AI — 2026-05-06","date":"2026-05-06T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-06-the-rundown-ai.md","filePath":"research/ai-news/2026-05/2026-05-06-the-rundown-ai.md","lastUpdated":1779898012000}'),r={name:"research/ai-news/2026-05/2026-05-06-the-rundown-ai.md"};function i(s,e,p,m,u,l){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="🗞️-the-rundown-ai-—-2026-05-06" tabindex="-1">🗞️ The Rundown AI — 2026-05-06 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-05-06" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-05-06&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="openai-s-ai-phone-just-jumped-the-line" tabindex="-1"><a href="https://www.therundown.ai/p/openai-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">OpenAI&#39;s AI phone just jumped the line</a> <a class="header-anchor" href="#openai-s-ai-phone-just-jumped-the-line" aria-label="Permalink to &quot;[OpenAI&#39;s AI phone just jumped the line](https://www.therundown.ai/p/openai-ai-phone-just-jumped-the-line)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-05-06</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. Amid intensifying competition with Anthropic, improved models, and efforts to kill “side hustles,” OpenAI is apparently looking at something closer to home — an AI agent phone.</p><p>Analyst Ming-Chi Kuo says the company is fast-tracking this device for 2027, with some notable capabilities. Good news for those wanting a stronger AI experience in their pockets. The question is: where does this leave the ongoing work with Jony Ive? Or is this the same device?</p><p>In today’s AI rundown:</p><p>OpenAI fast-tracks its ‘AI agent phone’</p><p>Anthropic’s AI agents for finance work</p><p>Make your Notion agents more autonomous</p><p>Home-based ‘mini’ AI data centers are coming</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>OPENAI</p><p>📱 <a href="https://x.com/mingchikuo/status/2051523855286776034?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">OpenAI fast-tracks ‘AI agent phone’</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: OpenAI is reportedly <a href="https://x.com/mingchikuo/status/2051523855286776034?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">accelerating</a> development of its first AI phone, now aiming for mass production in the first half of 2027, which is a full year earlier than previously reported, according to supply chain analyst Ming-Chi Kuo.</p><p>The details:</p><p>Kuo says the timeline shift is likely driven by OAI’s IPO ambitions (strong hardware could strengthen investor pitch) and rising competition in AI phones.</p><p>The phone’s standout spec will be its image signal processor, with an enhanced HDR pipeline to improve AI agents’ real-world visual sensing.</p><p>MediaTek is positioned to be the sole chip supplier, with the device using two AI processors to handle vision and language tasks simultaneously.</p><p>Kuo also added that OpenAI’s combined 2027–28 shipments of this phone could touch 30M, if the development stays on track.</p><p>Why it matters: Controlling hardware and OS could be the key to a true agentic phone. But if OpenAI’s AI phone is closer than we thought, where does this leave the device it’s building with Jony Ive’s io? OpenAI <a href="https://www.therundown.ai/p/openai-jony-ive-join-forces-in-6-5b-acquisition?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">acquired</a> io last year with much fanfare to go “beyond screens,” but nothing concrete has appeared so far <a href="https://www.therundown.ai/p/what-openai-and-jony-ive-are-building?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">except a few rumors</a>.</p><p>TOGETHER WITH LAMBDA</p><p>⚡ <a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer">How to push Model FLOPS Utilization past 50%</a></p><p><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Most large-scale training runs operate at just 35–45% Model FLOPS Utilization, meaning teams pay for more than twice the compute they actually use. Lambda’s engineers benchmarked Llama 3.1 models from 8B to 405B on NVIDIA Blackwell GPUs to trace efficiency loss to its root causes.</p><p>Efficiency losses were traced to:</p><p>Memory overhead capping effective throughput</p><p>Parallelism strategies misaligned with the hardware</p><p>Serialized communication stalling GPU cycles</p><p><a href="https://lambda.ai/llama-3-1-blackwell-mfu-benchmarks?utm_source=rundown-ai&amp;utm_medium=newsletter&amp;utm_campaign=2026-03-mfu-whitepaper&amp;utm_content=main-ad-may-6" target="_blank" rel="noreferrer">Get the guide</a>.</p><p>ANTHROPIC</p><p>🤑 <a href="https://www.anthropic.com/news/finance-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Anthropic’s AI agents for finance work</a></p><p><a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"></a></p><p>Image source: Anthropic</p><p>The Rundown: Anthropic just <a href="https://www.anthropic.com/news/finance-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">unveiled</a> 10 ready-to-run AI agents aimed squarely at financial services and insurance — capable of handling work ranging from building pitchbooks and screening KYC files to reviewing earnings and valuations.</p><p>The details:</p><p>Each agent comes with task-specific domain skills and instructions, connectors to relevant data sources, and add-on Claude models for sub-tasks.</p><p>Firms can adapt any agent of their choice to their own modeling conventions, risk policies, and approval flows — while staying in the loop 24/7.</p><p>The agents can be used as plugins within Claude Cowork or Claude Code on desktop, or as cookbooks, running as Managed Agents on the Claude platform.</p><p>Claude is also getting an add-in for Microsoft 365 as well as data connectors from Dun &amp; Bradstreet, Verisk, IBISWorld, and other financial services partners.</p><p>Why it matters: Development, <a href="https://www.anthropic.com/news/claude-code-security?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">cybersecurity</a>, <a href="https://www.therundown.ai/p/claude-comes-for-the-design-stack?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">design</a>, and now finance. Anthropic is going domain by domain, meeting businesses where they are instead of selling a general model and letting them figure it out. Its <a href="https://www.anthropic.com/news/enterprise-ai-services-company?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">new $1.5B joint venture</a> alongside Wall Street giants reinforces this strategy, further fueling its race with OpenAI.</p><p>AI TRAINING</p><p>🤖 <a href="https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Make your Notion agents more autonomous</a></p><p><a href="https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn a hidden workflow that will make your Notion Agents more autonomous and powerful than they are by default. This lets you wake up any agent, give it tasks, and then get a report on what it did.</p><p>Step-by-step:</p><p>Create a Notion agent from the “Agents” option in the sidebar. Then, open a database for the agent’s prompt and task reports. Ours is called “reports”</p><p>Click the New dropdown, open Templates, and create a @Today template (ours was Daily Summary). @Today makes duplicates inherit the current date</p><p>Set the properties, write task instructions in the page body, and @ mention the agent, so the duplicate triggers it. Remember to stop the agent when doing this, so it doesn’t overwrite the template</p><p>From the template, click New template, then Duplicate, and pick a cadence. We run ours daily at 7 a.m. A small blue icon next to the template shows it’s live</p><p>Pro tip: Try setting up daily debriefs, weekly reports, and email automations. Now you can route them all through the same planning agent.</p><p>PRESENTED BY IBM</p><p>🔌 <a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Rewire the C-suite for an AI-first world</a></p><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Most leaders know AI will reshape their business, but few have a clear playbook for how. An IBM Institute of Business Value analysis reveals 5 plays that CEOs must fulfill now for payoffs by 2030.</p><p>To lead in an AI-first landscape, surveyed CEOs suggest:</p><p>Customize your AI mix, not just your AI models</p><p>Hire a Chief AI Officer if you haven’t already</p><p>Orchestrate intelligence — both artificial and human</p><p><a href="https://www.ibm.com/thought-leadership/institute-business-value/en-us/c-suite-study/ceo?utm_content=CXOWW&amp;p1=Display&amp;p2=445741634&amp;p3=247627917&amp;utm_term=20AXK&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Get deeper details in the 2026 CEO Study</a>.</p><p>AI DATA CENTERS</p><p>🏘️ <a href="https://www.businesswire.com/news/home/20260414372626/en/SPAN-Announces-XFRA-a-Distributed-Data-Center-Solution-to-Close-the-Speed-to-Power-Gap-for-AI-Compute-Demand?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Home-based ‘mini’ AI data centers are coming</a></p><p>Image source: Span</p><p>The Rundown: California startup Span is <a href="https://www.businesswire.com/news/home/20260414372626/en/SPAN-Announces-XFRA-a-Distributed-Data-Center-Solution-to-Close-the-Speed-to-Power-Gap-for-AI-Compute-Demand?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">teaming up</a> with Nvidia to install mini AI data centers on the walls of residential homes and small businesses, tapping unused electrical capacity on local grids to meet surging AI compute demand.</p><p>The details:</p><p>Span has developed XFRA, small compute nodes that mount on the exterior walls of homes, alongside accompanying HVAC and electrical systems.</p><p>Nvidia is providing its liquid-cooled RTX PRO 6000 Blackwell Server Edition GPUs to power each XFRA box, ensuring noiseless computing for AI workloads.</p><p>Span told <a href="https://www.cnbc.com/2026/05/05/nvidia-pulte-span-mini-data-centers-on-homes.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">CNBC</a> it can install 8,000 XFRA units 6x faster and at one-fifth the cost of building a comparable 100MW centralized data center facility.</p><p>Currently, the company is working with PulteGroup, one of the largest U.S. homebuilders, to test the box and its economics in newly built communities.</p><p>Why it matters: Grid strain from data centers is real, and Span’s boxes could spread the load while tapping only unused capacity. But public response is an open question — not all will love the idea of a data center box mounted where kids play, especially when alternatives like <a href="https://www.rundown.ai/articles/ai-data-centers-head-for-the-ocean?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">ocean</a>- and <a href="https://www.rundown.ai/articles/googles-ai-space-moonshot?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">space-based</a> data centers are also in sight.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🚀 <a href="https://blog.box.com/introducing-box-automate-ai-powered-workflow-orchestration?utm_source=newsletter&amp;utm_medium=paidinfluencer&amp;utm_theme=icm&amp;utm_campaign=FY27_Q2_RundownAI_AutomateNewTool" target="_blank" rel="noreferrer">Box Automate</a> - Orchestrate agentic workflow automation, securely and at scale*</p><p>🎨 <a href="https://www.rundown.ai/tools/pomelli?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Pomelli</a> - Make product-specific campaigns with Google’s AI marketing tool</p><p>🖼️ <a href="https://lumalabs.ai/api?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Uni 1.1</a> - Luma’s new image generation and editing AI that nears the frontier</p><p>🎮️ <a href="https://www.astrocade.com/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Astrocade</a> - Platform to create shareable games with AI</p><p>*Sponsored Listing</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>OpenAI’s GPT-5.5-Instant <a href="https://openai.com/index/gpt-5-5-instant/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">started</a> rolling out to all ChatGPT users, bringing improved performance, stronger memory, and more personalized, concise responses.</p><p>Microsoft <a href="https://www.microsoft.com/en-us/microsoft-365/blog/2026/05/05/copilot-cowork-from-conversation-to-action-across-skills-integrations-and-devices/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">expanded</a> its Copilot Cowork agentic system to iOS and Android, while adding built-in skills for common tasks and data plugins for business systems.</p><p>Apple <a href="https://www.bbc.com/news/articles/c0j2nydnzy7o?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">agreed</a> to pay some U.S. iPhone buyers a collective $250M to settle a class action lawsuit over misleading claims about its new AI Siri, but admitted no wrongdoing.</p><p>Perplexity AI <a href="https://x.com/perplexity_ai/status/2051693893473935372?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">launched</a> Computer for Professional Finance, bringing licensed data and 35 dedicated workflows to its agentic system to help analysts handle routine work.</p><p>Anthropic reportedly <a href="https://www.theinformation.com/articles/anthropic-commits-spending-200-billion-googles-cloud-chips?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">committed</a> to spending $200B on Google’s cloud and chips over the next five years, now making 40%+ of Google’s revenue backlog.</p><p>Coinbase CEO Brian Armstrong <a href="https://x.com/brian_armstrong/status/2051616759145185723?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">said</a> the company is cutting 14% of its workforce, ~700 people, as it shifts to AI-native teams, agent-driven workflows, and leaner ops.</p><p>COMMUNITY</p><p>🤝 <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Schy W. in Springfield, IL:</p><p>&quot;I went to a music festival — multiple stages, music over several days. Many bands had more than one set time/location. I fed Claude the festival’s schedule PDF and told it to extract the information, but to ignore autograph signing and music workshops. I then read off a list of bands I wanted to see and followed up with a subset of those that I absolutely did not want to miss. I requested a schedule that would plan out where I should be to maximize the number of bands I could reasonably see with a simple prompt.</p><p>It understood the mission and in one stroke produced a fantastic spreadsheet optimizing my time and noting my priorities, stages, times, partial sets, if a band has another set, and explained the decision-making rationale.”</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.therundown.ai/p/ai-data-centers-head-for-the-ocean?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">AI data centers head for the ocean</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/gamestop-wild-bid-to-buy-ebay?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">GameStop&#39;s wild bid to buy eBay</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/meta-buys-a-humanoid-brain?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Meta buys a humanoid brain</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/use-this-hidden-feature-to-make-your-notion-agents-autonomous?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-ai-phone-just-jumped-the-line" target="_blank" rel="noreferrer">Make your Notion agents more autonomous</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',104)])])}const w=t(r,[["render",i]]);export{d as __pageData,w as default};
